import 'family-chart/styles/family-chart.css'
import type { TreeDatum, Tree } from 'family-chart';


export default function create() {
  const card_width = 200;
  const card_height = 70;

  const data = dataBuilder.Datasets.default()

  const chart = createChart('#FamilyChart', data)
    .setAncestryDepth(1)
    .setProgenyDepth(1)
    .setShowSiblingsOfMain()

  const card = chart.setCardHtml()
    .setCardDisplay([['first name', 'last name']])
    .setCardWidth(card_width)
    .setCardHeight(card_height)
    .setOnHoverPathToMain()

  card.setCardDim({
    width: card_width,
    height: card_height
  })

  function fullMiniTreeFilter(td: TreeDatum, tree: Tree, is_ancestry?: boolean) {
    return isLastLevelAncestry() || isLastLevelProgeny()

    function isLastLevelAncestry() {
      return td.is_ancestry && tree.meta.max_depth.ancestry === td.depth && is_ancestry
    }

    function isLastLevelProgeny() {
      return !td.is_ancestry && tree.meta.max_depth.progeny === td.depth && !is_ancestry
    }
  }

  const full_mini_tree_plugin = new FullMiniTreePlugin({
    member_card_width: card_width,
    member_card_height: card_height,
    onCardClick: (event, d) => {
      chart.updateMainId(d.data.id)
      chart.updateTree({})
    },
    memberCardTooltip: {
      cont: chart.cont,
      fullCardRenderer: card.getCard()
    },
    sortChildrenFunction: (a, b) => a.data['first name'].localeCompare(b.data['first name']),
    generateFilter: fullMiniTreeFilter,
    add_spacing_for_last_level_ancestry: true,
    add_spacing_for_last_level_progeny: true,
    align_children_with_member: true
  });

  const mini_tree_plugin = new MiniTreePlugin({
    member_card_width: card_width,
    member_card_height: card_height,
    generateFilter: (...params: Parameters<typeof fullMiniTreeFilter>) => {
      return !fullMiniTreeFilter(...params)
    },
    
    memberCardTooltip: {
      cont: chart.cont,
      fullCardRenderer: card.getCard(),
    },
    onCardClick: (event, d) => {
      chart.updateMainId(d.data.id)
      chart.updateTree({})
    },
  })

  chart.use(full_mini_tree_plugin)
  chart.use(mini_tree_plugin)

  chart.updateTree({})

  return { chart, card }
}
