import 'family-chart/styles/family-chart.css'
import "../src/kinship.css"


export default function create() {
  const data = dataBuilder.generateFamilyTree({
    ancestryDepth: 4,
    progenyDepth: 3,
    childrenPerPerson: 2
  });

  const chart = createChart('#FamilyChart', data)

  document.querySelector('.f3-nav-cont')!.appendChild(createBtn())

  chart.setCardHtml()
    .setCardDisplay([['first name']])


  const kinshipPlugin = new KinshipPlugin()

  // Set the person from whose perspective we calculate kinships
  kinshipPlugin.setSelfId(chart.getMainDatum().id);

  kinshipPlugin.setInfoOptions({
    title: 'Kinship',
    getLabel: (d: Datum) => d.data['first name'],
  })

  chart.setAfterUpdate(function () {
    const main_id = chart.getMainDatum().id
    const kinshipPopup = kinshipPlugin.createPopup(main_id, chart.store.getData(), getBtn().parentElement!)
    getBtn().addEventListener('click', (e: MouseEvent) => kinshipPopup.activate(e))
  });

  function createBtn() {
    const btnContainer = document.createElement('div')
    btnContainer.style.zIndex = '1000'
    const btn = document.createElement('button')
    btn.id = 'f3-kinship-tree-btn'
    btn.innerText = 'Kinship-tree'
    btnContainer.appendChild(btn)
    return btnContainer
  }

  function getBtn() {
    return document.querySelector('#f3-kinship-tree-btn') as HTMLElement
  }

  chart.updateTree({ transition_cascade: true });

  return { chart }
}
  
