import 'family-chart/styles/family-chart.css'

export default function create() {
  const data = dataBuilder.Datasets.default()

  // For the example, let's add some marriage date to one of the relationships
  addMarriageDate(data[0].id, '1995')
  addMarriageDate(data[0].rels.parents[0], '1973')


  const chart = createChart('#FamilyChart', data)

  const plugin = new SpouseLinkTextPlugin({
    text: (sp1: TreeDatum, sp2: TreeDatum) => {
      return sp2.data.rel_data[sp1.data.id]?.marriage_date || '';
    }
  });
  chart.use(plugin);

  chart.setCardHtml()

  chart.updateTree({ transition_cascade: true });

  function addMarriageDate(d_id: any, date: string) {
    const d = data.find(d => d.id === d_id)!
    const spouse_id = d.rels.spouses[0]
    if (spouse_id) {
      d.rel_data = { [spouse_id]: { marriage_date: date } }
      data.find(d => d.id === spouse_id)!.rel_data = { [d.id]: { marriage_date: date } }
    }
  }

  return { chart, plugin }
}
